import React from 'react';
import { Card, CardContent, Box, Typography, Stack, LinearProgress } from '@mui/material';
import response from './response.json';

interface PackingProgress {
  itemsPacked: number;
  totalItems: number;
  percentage: number;
}

interface UpcomingTrip {
  destination: string;
  departureDate: string;
  daysUntilDeparture: number;
  packingProgress: PackingProgress;
}

interface TravelData {
  upcomingTrip: UpcomingTrip;
}

export default function Widget() {
  const travelData = response.data as TravelData;
  const { upcomingTrip } = travelData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 380, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FF5722', fontWeight: 600 }}>
              Upcoming Trip
            </Typography>
            <Typography variant="body1" sx={{ color: '#3F51B5', mt: 1 }}>
              Destination: {upcomingTrip.destination}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Departure: {upcomingTrip.departureDate}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Days Until Departure: {upcomingTrip.daysUntilDeparture}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 0.5 }}>
              Packing Progress
            </Typography>
            <LinearProgress
              variant="determinate"
              value={upcomingTrip.packingProgress.percentage}
              sx={{
                height: 8,
                borderRadius: 4,
                bgcolor: '#E3F2FD',
                '& .MuiLinearProgress-bar': {
                  bgcolor: '#3F51B5',
                  borderRadius: 4,
                },
              }}
            />
            <Typography variant="caption" sx={{ mt: 0.5, display: 'block', color: '#3F51B5', fontWeight: 600 }}>
              {upcomingTrip.packingProgress.itemsPacked}/{upcomingTrip.packingProgress.totalItems} items packed
            </Typography>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
